// MARK: - Security Utilities
extension Data {
    static func randomBytes(count: Int) -> Data {
        var bytes = [UInt8](repeating: 0, count: count)
        _ = SecRandomCopyBytes(kSecRandomDefault, count, &bytes)
        return Data(bytes)
    }
    
    func sha256() -> Data {
        return Data(SHA256.hash(data: self))
    }
}

// MARK: - Financial Service Manager
class FinancialServiceManager {
    static let shared = FinancialServiceManager()
    
    private let processor = TransactionProcessor.shared
    
    func transferFunds(fromAccountId: String, toAccountId: String, amount: Double) -> Bool {
        guard let fromAccount = processor.getAccountBalance(accountId: fromAccountId) else {
            return false
        }
        
        guard fromAccount >= amount else {
            return false
        }
        
        let debitTransaction = Transaction(
            id: UUID().uuidString,
            amount: amount,
            type: .debit,
            date: Date(),
            description: "Transfer to \(toAccountId)",
            accountId: fromAccountId
        )
        
        let creditTransaction = Transaction(
            id: UUID().uuidString,
            amount: amount,
            type: .credit,
            date: Date(),
            description: "Transfer from \(fromAccountId)",
            accountId: toAccountId
        )
        
        let debitSuccess = processor.processTransaction(debitTransaction)
        let creditSuccess = processor.processTransaction(creditTransaction)
        
        return debitSuccess && creditSuccess
    }
    
    func getAccountBalance(accountId: String) -> Double? {
        return processor.getAccountBalance(accountId: accountId)
    }
    
    func getTransactionHistory(accountId: String) -> [Transaction] {
        return processor.getTransactionHistory(accountId: accountId)
    }
}

